+      const viewKey = getViewKey(view)
+      const existingIndex = prev.stack.findIndex(v => getViewKey(v) === viewKey)
+
+      if (existingIndex >= 0) {
+        // Navigate to existing view instead of pushing duplicate
+        const newStack = prev.stack.slice(0, existingIndex + 1)
