+          ...prev,
+          stack: newStack,
+          currentView: newStack[newStack.length - 1] }
+      }
+
+      // Push new view onto the stack
+      return {
+        ...prev,
+        stack: [...prev.stack, view],
+        currentView: view }
+    })
+  }, [])
